import { KernelFunction } from '@semantic-kernel/core';

export const draftGenerationPlugin = KernelFunction.fromPromptFunction(
  {
    name: 'generate_draft',
    description: 'Generate professional email draft',
    parameters: {
      emailContent: { type: 'string', description: 'Original email' },
      intent: { type: 'string', description: 'Detected intent' }
    }
  },
  async (context, props) => {
    const prompt = `Generate professional response to: ${props.emailContent}. Intent: ${props.intent}`;
    const result = await context.variables.set('draft', await context.llm.invokePrompt(prompt));
    return result;
  }
);

from semantic_kernel.skill_definition import kernel_function

class AttachmentPlugin:
    @kernel_function(
        description="Handle email attachments safely",
        name="process_attachments"
    )
    def process_attachments(self, attachments: list, email_intent: str) -> str:
        """Scans and categorizes attachments based on email intent"""
        safe_attachments = []
        for attachment in attachments:
            if self.is_safe(attachment) and email_intent != 'archive':
                safe_attachments.append(attachment['filename'])
        return f"|attachments={','.join(safe_attachments)}"

import { KernelFunction } from '@semantic-kernel/core';

export const sendApprovalPlugin = KernelFunction.fromPromptFunction(
  {
    name: 'request_approval',
    description: 'Request human approval for sensitive emails',
    parameters: {
      draft: { type: 'string', description: 'Generated draft' },
      recipient: { type: 'string', description: 'Email recipient' }
    }
  },
  async (context, props) => {
    const isSensitive = props.recipient.includes('@executive.com') || props.draft.includes('confidential');
    return isSensitive ? 'requires_approval' : 'auto_send';
  }
);

