import vex

from semantic_kernel.filters import KernelResultFilter

@vex.workflow(name="email_assistant_verification")
def verify_email_output(result: str, context: dict) -> dict:
    checks = [
        vex.pii_filter(block=True, categories=['EMAIL_ADDRESS', 'PHONE_NUMBER']),
        vex.semantic_check(prompt="Is this email tone professional?", threshold=0.8),
        vex.schema_validation(schema={
            "type": "object",
            "properties": {"intent": {"type": "string"}, "tone": {"type": "string"}}
        })
    ]
    return vex.run(result, checks, context)

# Register as kernel filter
kernel.add_filter(KernelResultFilter(verify_email_output))

import { Vex } from 'vex-sdk';

const vex = new Vex({ apiKey: process.env.VEX_API_KEY });

kernel.addFilter({
  onFunctionResult: async (result, context) => {
    if (context.function.name === 'planner') {
      const plan = result.value as string;
      const validation = await vex.run(plan, [
        vex.regex_match('.*approval.*|.*review.*', 'Must include approval step'),
        vex.semantic_check('Plan contains all required email workflow steps', 0.9)
      ], { useCase: 'email_assistant' });

      if (!validation.passed) {
        throw new Error('Invalid execution plan: ' + validation.issues);
      }
    }
    return result;
  }
});
